#include "controller.h"

#define CONTROLLER_TIMEOUT_THRESHOLD_MS CONTROLLER_SENSOR_TIMEOUT_MS

static void controller_set_safe_vent(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller->compressor_on = false;
    controller->vent_open = true;
    controller->state = CONTROLLER_STATE_SAFE_VENT;
}

static bool controller_is_stale(const controller_t *controller, uint32_t now_ms)
{
    uint32_t pressure_age;
    uint32_t door_age;

    if (controller == 0) {
        return false;
    }

    if (!controller->has_valid_pressure || !controller->has_valid_door) {
        return false;
    }

    pressure_age = now_ms - controller->last_pressure_ms;
    door_age = now_ms - controller->last_door_ms;
    return (pressure_age > CONTROLLER_TIMEOUT_THRESHOLD_MS) || (door_age > CONTROLLER_TIMEOUT_THRESHOLD_MS);
